        if (has_switch == 0) {
            for (auto& [v, w] : adj[u]) {
                long long new_cost = cost + 2 * w;
                if (new_cost < dist[v][1]) {
                    dist[v][1] = new_cost;
                    pq.push({new_cost, {v, 1}});
                }
            }
        }
    }

    return -1;
