using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        adj[u].push_back({v, w});
    }

    // Dijkstra's algorithm with state (node, has_switch)
    // has_switch: 0 means switch not used, 1 means switch used
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<>> pq;
    vector<vector<long long>> dist(n, vector<long long>(2, LONG_MAX));
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long u = pq.top().second.first;
        long long has_switch = pq.top().second.second;
        pq.pop();

        if (u == n - 1) return cost;

        if (cost > dist[u][has_switch]) continue;

        // Traverse normal edges
        for (auto& [v, w] : adj[u]) {
            long long new_cost = cost + w;
            if (new_cost < dist[v][has_switch]) {
                dist[v][has_switch] = new_cost;
                pq.push({new_cost, {v, has_switch}});
            }
        }

        // If switch is not used, try to flip the edge
        if (has_switch == 0) {
            for (auto& [v, w] : adj[u]) {
                long long new_cost = cost + 2 * w;
                if (new_cost < dist[v][1]) {
                    dist[v][1] = new_cost;
                    pq.push({new_cost, {v, 1}});
                }
            }
        }
    }

    return -1;
}

